mapper.select:
SELECT status
FROM disposal
WHERE disposal_id = #{disposalId}

mapper.update:
UPDATE disposal
SET status='REJECTED',
    reject_reason=#{rejectReason}
WHERE disposal_id = #{disposalId}
  AND status = 'REQUESTED'

UPDATE inventory_lot
SET current_qty=current_qty - #{disposalQty}
WHERE inventory_lot_id = #{inventoryLotId}
  AND current_qty >= #{disposalQty}
